{"metadata":{"kernelspec":{"display_name":"Python 3","language":"python","name":"python3"},"language_info":{"name":"python","version":"3.12.12","mimetype":"text/x-python","codemirror_mode":{"name":"ipython","version":3},"pygments_lexer":"ipython3","nbconvert_exporter":"python","file_extension":".py"},"kaggle":{"accelerator":"none","dataSources":[{"sourceType":"competition","sourceId":128431,"databundleVersionId":15477148}],"dockerImageVersionId":31259,"isInternetEnabled":true,"language":"python","sourceType":"notebook","isGpuEnabled":false}},"nbformat_minor":4,"nbformat":4,"cells":[{"cell_type":"markdown","source":"Messy Mashup — Ensemble Inference Script\n\nNotebook trained locally, inference notebook:\n  - AST with 5-crop TTA\n  - CNN with 3-chunk TTA (start/centre/end)\n  - GPU mel transform\n  - Weighted ensemble -> submission.csv\n\n***P.S.: GPU quota end, will add the rest code and run again as soon as GPU comes back.***","metadata":{}},{"cell_type":"markdown","source":"## Imports","metadata":{}},{"cell_type":"code","source":"import os, random, warnings\nimport numpy as np\nimport pandas as pd\nimport torch\nimport torch.nn as nn\nimport torchaudio\nimport torchaudio.transforms as T\nimport torchvision.models as models\nimport librosa\nfrom pathlib import Path\nfrom tqdm import tqdm\nfrom transformers import ASTFeatureExtractor, ASTForAudioClassification\n\nwarnings.filterwarnings('ignore')","metadata":{"trusted":true},"outputs":[],"execution_count":null},{"cell_type":"markdown","source":"## Config","metadata":{}},{"cell_type":"code","source":"BASE_PATH    = '/kaggle/input/jan-2026-dl-gen-ai-project/messy_mashup'\nMASHUPS_PATH = os.path.join(BASE_PATH, 'mashups')\nTEST_CSV     = os.path.join(BASE_PATH, 'test.csv')\nCKPT_DIR     = '/kaggle/input/datasets/shibashishbanerjee/checkpoints'\nOUTPUT_CSV   = '/kaggle/working/submission.csv'\n\nDEVICE  = 'cuda' if torch.cuda.is_available() else 'cpu'\nUSE_AMP = True\n\nGENRES   = ['blues','classical','country','disco','hiphop',\n            'jazz','metal','pop','reggae','rock']\nid2label = {i: g for i, g in enumerate(GENRES)}\nNUM_LABELS = len(GENRES)\n\n# AST config\nAST_MODEL_NAME  = 'MIT/ast-finetuned-audioset-10-10-0.4593'\nAST_SAMPLE_RATE = 16000\nAST_DURATION    = 20\nAST_MAX_LENGTH  = AST_SAMPLE_RATE * AST_DURATION\nAST_N_TTA       = 5\n\n# CNN config\nCNN_SAMPLE_RATE = 22050\nCNN_DURATION    = 5.0\nCNN_N_SAMPLES   = int(CNN_SAMPLE_RATE * CNN_DURATION)\nCNN_N_FFT       = 2048\nCNN_HOP_LEN     = 512\nCNN_N_MELS      = 128\n\n# Ensemble weights\nENSEMBLE_WEIGHTS = {\n    'AST'            : 0.40,\n    'CustomCNN'      : 0.15,\n    'AudioResNet34'  : 0.20,\n    'EfficientNetB0' : 0.25,\n}\n\n# Checkpoint filenames inside CKPT_DIR\nCKPT_FILES = {\n    'AST'            : 'messy-mashup_checkpoints_ast_best_phase2.pth',\n    'CustomCNN'      : 'CustomCNN_best.pth',\n    'AudioResNet34'  : 'messy-mashup_checkpoints_checkpoints_AudioResNet34_best.pth',\n    'EfficientNetB0' : 'EfficientNetB0_best.pth',\n}\n\nprint(f\"Device: {DEVICE} | AMP: {USE_AMP}\")","metadata":{"trusted":true},"outputs":[],"execution_count":null},{"cell_type":"markdown","source":"## Model Architectures","metadata":{}},{"cell_type":"code","source":"class CustomCNN(nn.Module):\n    def __init__(self, num_classes=NUM_LABELS):\n        super().__init__()\n        self.features = nn.Sequential(\n            nn.Conv2d(1,32,3,padding=1), nn.BatchNorm2d(32), nn.ReLU(), nn.MaxPool2d(2),\n            nn.Conv2d(32,64,3,padding=1), nn.BatchNorm2d(64), nn.ReLU(), nn.MaxPool2d(2),\n            nn.Conv2d(64,128,3,padding=1), nn.BatchNorm2d(128), nn.ReLU(), nn.MaxPool2d(2),\n        )\n        self.classifier = nn.Sequential(\n            nn.AdaptiveAvgPool2d(1), nn.Flatten(),\n            nn.Linear(128,256), nn.ReLU(), nn.Dropout(0.3), nn.Linear(256,num_classes)\n        )\n    def forward(self, x): return self.classifier(self.features(x))\n\n\nclass AudioResNet(nn.Module):\n    def __init__(self, num_classes=NUM_LABELS):\n        super().__init__()\n        self.resnet = models.resnet34(weights=None)\n        orig_w = self.resnet.conv1.weight.clone()\n        self.resnet.conv1 = nn.Conv2d(1,64,7,2,3,bias=False)\n        with torch.no_grad():\n            self.resnet.conv1.weight[:,0] = orig_w.mean(dim=1)\n        self.resnet.fc = nn.Linear(self.resnet.fc.in_features, num_classes)\n    def forward(self, x): return self.resnet(x)\n\n\nclass AudioEfficientNet(nn.Module):\n    def __init__(self, num_classes=NUM_LABELS):\n        super().__init__()\n        self.model = models.efficientnet_b0(weights=None)\n        orig_w = self.model.features[0][0].weight.clone()\n        self.model.features[0][0] = nn.Conv2d(1,32,3,stride=2,padding=1,bias=False)\n        with torch.no_grad():\n            self.model.features[0][0].weight[:,0] = orig_w.mean(dim=1)\n        self.model.classifier[1] = nn.Linear(self.model.classifier[1].in_features, num_classes)\n    def forward(self, x): return self.model(x)","metadata":{"trusted":true},"outputs":[],"execution_count":null},{"cell_type":"markdown","source":"## GPU Mel Trnasform","metadata":{}},{"cell_type":"code","source":"gpu_mel_transform = nn.Sequential(\n    T.MelSpectrogram(sample_rate=CNN_SAMPLE_RATE, n_fft=CNN_N_FFT,\n                     hop_length=CNN_HOP_LEN, n_mels=CNN_N_MELS),\n    T.AmplitudeToDB()\n).to(DEVICE)\n","metadata":{"trusted":true},"outputs":[],"execution_count":null},{"cell_type":"markdown","source":"## Checkpoint Loaders","metadata":{}},{"cell_type":"code","source":"def load_checkpoint(model, name):\n    path = os.path.join(CKPT_DIR, CKPT_FILES[name])\n    if not os.path.exists(path):\n        print(f\"[WARN] Checkpoint not found -- skipping {name}: {path}\")\n        return None\n    ckpt = torch.load(path, map_location=DEVICE)\n    if isinstance(ckpt, dict) and 'model_state_dict' in ckpt:\n        state = ckpt['model_state_dict']\n        extra = f\"  (val F1: {ckpt.get('val_f1', '?')})\"\n    else:\n        state = ckpt\n        extra = \"\"\n    state = {k.replace('module.', ''): v for k, v in state.items()}\n    model.load_state_dict(state, strict=True)\n    model.eval().to(DEVICE)\n    print(f\"[OK] Loaded {name}{extra}\")\n    return model","metadata":{"trusted":true},"outputs":[],"execution_count":null},{"cell_type":"markdown","source":"## AST Audio Helpers","metadata":{}},{"cell_type":"code","source":"def ast_load_audio(path):\n    audio, _ = librosa.load(path, sr=AST_SAMPLE_RATE, mono=True)\n    return audio.astype(np.float32)\n\ndef ast_normalize(audio):\n    return audio / (np.max(np.abs(audio)) + 1e-6)\n\ndef ast_crop_random(audio):\n    if len(audio) >= AST_MAX_LENGTH:\n        start = random.randint(0, len(audio) - AST_MAX_LENGTH)\n        return audio[start : start + AST_MAX_LENGTH]\n    return np.pad(audio, (0, AST_MAX_LENGTH - len(audio)))","metadata":{"trusted":true},"outputs":[],"execution_count":null},{"cell_type":"markdown","source":"## Inference Helpers","metadata":{}},{"cell_type":"code","source":"def ast_predict_proba(ast_model, feature_extractor, audio):\n    # 5-crop TTA\n    probs = []\n    for _ in range(AST_N_TTA):\n        c   = ast_normalize(ast_crop_random(audio))\n        inp = feature_extractor(c, sampling_rate=AST_SAMPLE_RATE, return_tensors='pt')\n        with torch.no_grad():\n            with torch.cuda.amp.autocast(enabled=USE_AMP):\n                out = ast_model(input_values=inp['input_values'].to(DEVICE))\n            probs.append(torch.softmax(out.logits, 1).cpu().numpy()[0])\n    return np.mean(probs, axis=0)\n\n\ndef cnn_predict_proba(cnn_model1, cnn_model2, cnn_model3, audio_path):\n    # 3-chunk TTA (start/centre/end)\n    try:\n        wav, sr = torchaudio.load(audio_path)\n        if sr != CNN_SAMPLE_RATE:\n            wav = torchaudio.functional.resample(wav, sr, CNN_SAMPLE_RATE)\n        wav = wav.mean(0).numpy()\n    except:\n        wav = np.zeros(CNN_N_SAMPLES)\n\n    L = len(wav)\n    n = CNN_N_SAMPLES\n    if L < n:\n        wav = np.pad(wav, (0, n - L))\n        L = n\n\n    chunks = [\n        wav[:n],\n        wav[max(0, L//2 - n//2) : max(0, L//2 - n//2) + n],\n        wav[L - n:]\n    ]\n    chunk_tensors = torch.stack([\n        torch.tensor(\n            c[:n] if len(c) >= n else np.pad(c, (0, n - len(c))),\n            dtype=torch.float32\n        ) for c in chunks\n    ]).unsqueeze(1).to(DEVICE)    # (3, 1, N)\n\n    specs = gpu_mel_transform(chunk_tensors.squeeze(1).unsqueeze(1))  # (3, 1, n_mels, T)\n\n    probs = []\n    with torch.no_grad():\n        with torch.cuda.amp.autocast(enabled=USE_AMP):\n            for m in [cnn_model1, cnn_model2, cnn_model3]:\n                out = m(specs)\n                probs.append(torch.softmax(out, 1).cpu().numpy())\n\n    # Each entry is (3, 10) -- average over 3 TTA chunks\n    p_cnn1 = np.mean(probs[0], axis=0)\n    p_cnn2 = np.mean(probs[1], axis=0)\n    p_cnn3 = np.mean(probs[2], axis=0)\n    return p_cnn1, p_cnn2, p_cnn3\n","metadata":{"trusted":true},"outputs":[],"execution_count":null},{"cell_type":"markdown","source":"## Final","metadata":{}},{"cell_type":"code","source":"# 1. Load AST\nprint(\"\\n[1/5] Loading AST ...\")\nast_feature_extractor = ASTFeatureExtractor.from_pretrained(AST_MODEL_NAME)\n_ast_base = ASTForAudioClassification.from_pretrained(\n    AST_MODEL_NAME,\n    num_labels=NUM_LABELS,\n    ignore_mismatched_sizes=True\n)\n_ast_base.to(DEVICE)\nckpt_ast = os.path.join(CKPT_DIR, CKPT_FILES['AST'])\nstate = torch.load(ckpt_ast, map_location=DEVICE)\nstate = {k.replace('module.', ''): v for k, v in state.items()}\n_ast_base.load_state_dict(state, strict=True)\n_ast_base.eval()\nprint(f\"[OK] Loaded AST from {ckpt_ast}\")","metadata":{"trusted":true},"outputs":[],"execution_count":null},{"cell_type":"code","source":"# 2. Load CNN models\nprint(\"\\n[2/5] Loading CustomCNN ...\")\ncnn_model1 = load_checkpoint(CustomCNN(), 'CustomCNN')\n\nprint(\"\\n[3/5] Loading AudioResNet34 ...\")\ncnn_model2 = load_checkpoint(AudioResNet(), 'AudioResNet34')\n\nprint(\"\\n[4/5] Loading EfficientNetB0 ...\")\ncnn_model3 = load_checkpoint(AudioEfficientNet(), 'EfficientNetB0')","metadata":{"trusted":true},"outputs":[],"execution_count":null},{"cell_type":"code","source":"# 3. Build file map from test.csv\nprint(\"\\n[5/5] Building test file map ...\")\ntest_df  = pd.read_csv(TEST_CSV)\nfile_map = {}\nfor f in Path(MASHUPS_PATH).glob(\"*.wav\"):\n    nums = ''.join(filter(str.isdigit, f.stem))\n    if nums:\n        file_map[int(nums)] = str(f)\nprint(f\"    Test samples: {len(test_df)} | Audio files found: {len(file_map)}\")","metadata":{"trusted":true},"outputs":[],"execution_count":null},{"cell_type":"code","source":"# 4. Ensemble inference\nprint(\"\\nRunning ensemble inference ...\")\nall_ids, all_preds = [], []\n\nfor idx in tqdm(range(len(test_df)), desc=\"Ensemble Inference\"):\n    row = test_df.iloc[idx]\n    try:\n        id_int = int(row['id'])\n    except:\n        id_int = int(''.join(filter(str.isdigit, str(row['id']))))\n\n    audio_path = file_map.get(id_int, os.path.join(MASHUPS_PATH, str(row['id'])))\n\n    try:\n        p_ast = ast_predict_proba(_ast_base, ast_feature_extractor,\n                                                 ast_load_audio(audio_path))\n        p_c1, p_c2, p_c3 = cnn_predict_proba(cnn_model1, cnn_model2, cnn_model3, audio_path)\n\n        ep = (ENSEMBLE_WEIGHTS['AST'] * p_ast +\n              ENSEMBLE_WEIGHTS['CustomCNN'] * p_c1  +\n              ENSEMBLE_WEIGHTS['AudioResNet34']  * p_c2  +\n              ENSEMBLE_WEIGHTS['EfficientNetB0'] * p_c3)\n\n        pred = id2label[int(np.argmax(ep))]\n    except Exception as e:\n        print(f\"  [WARN] Failed on id={id_int}: {e}\")\n        pred = 'rock'\n\n    all_ids.append(row['id'])\n    all_preds.append(pred)","metadata":{"trusted":true},"outputs":[],"execution_count":null},{"cell_type":"code","source":"# 5. Save submission\nsubmission = pd.DataFrame({'id': all_ids, 'genre': all_preds})\nos.makedirs(os.path.dirname(OUTPUT_CSV), exist_ok=True)\nsubmission.to_csv(OUTPUT_CSV, index=False)\nprint(f\"\\nSubmission saved -> {OUTPUT_CSV}\")\nprint(f\"Total predictions: {len(submission)}\")\nprint(\"\\nGenre distribution:\")\nprint(submission['genre'].value_counts().to_string())","metadata":{"trusted":true},"outputs":[],"execution_count":null}]}